
import { defineComponent, ref } from "vue";

export default defineComponent({
  setup() {
    const currentActiveTab = ref("Personal");

    const toggleTab = (tab: string) => {
      currentActiveTab.value = tab;
    };

    const tabCss = ref(
      "flex items-center justify-center px-3 py-2 font-medium text-gray-800 uppercase transition-colors duration-200 transform rounded-lg dark:bg-gray-600 focus:outline-none dark:text-gray-200 hover:bg-gray-200 hover:text-grey-400"
    );
    const ActiveTabCss = ref(
      "px-3 py-2 font-medium text-gray-800 uppercase transition-colors duration-200 bg-gray-200 transform rounded-lg focus:outline-none dark:text-gray-200 dark:hover:bg-gray-600"
    );

    return {
      toggleTab,
      currentActiveTab,
      tabCss,
      ActiveTabCss,
    };
  },
});
